Here is a complete, single-file HTML solution using **Three.js**. You can save this code as an `.html` file (e.g., `house.html`) and open it in any modern web browser to see the 3D house.

### Three.js 3D House Code

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>3D House Model</title>
    <style>
        body { margin: 0; overflow: hidden; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: sans-serif;
            pointer-events: none;
            text-shadow: 1px 1px 2px black;
        }
    </style>
</head>
<body>
    <div id="info">Click and drag to rotate • Scroll to zoom</div>

    <!-- Import Three.js from a CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // 1. Scene Setup
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 10, 50);

        const camera = new THREE.PerspectiveCamera(75, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(5, 5, 5);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true;
        document.body.appendChild(renderer.domElement);

        // 2. Controls
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;

        // 3. Lighting
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // 4. Materials
        const wallMaterial = new THREE.MeshStandardMaterial({ color: 0x8B4513 }); // Brown
        const roofMaterial = new THREE.MeshStandardMaterial({ color: 0x800000 }); // Dark Red
        const glassMaterial = new THREE.MeshStandardMaterial({ color: 0xADD8E6, transparent: true, opacity: 0.6 });
        const floorMaterial = new THREE.MeshStandardMaterial({ color: 0x228B22 }); // Green grass

        // 5. Building the House
        const houseGroup = new THREE.Group();

        // Floor
        const floorGeo = new THREE.BoxGeometry(10, 1, 10);
        const floor = new THREE.Mesh(floorGeo, floorMaterial);
        floor.position.y = -0.5;
        floor.receiveShadow = true;
        houseGroup.add(floor);

        // Main Body
        const bodyGeo = new THREE.BoxGeometry(6, 4, 6);
        const body = new THREE.Mesh(bodyGeo, wallMaterial);
        body.position.y = 2;
        body.castShadow = true;
        body.receiveShadow = true;
        houseGroup.add(body);

        // Roof
        const roofGeo = new THREE.ConeGeometry(5, 3, 4);
        const roof = new THREE.Mesh(roofGeo, roofMaterial);
        roof.position.y = 5.5;
        roof.rotation.y = Math.PI / 4; // Rotate to align with box
        roof.castShadow = true;
        houseGroup.add(roof);

        // Windows
        const windowGeo = new THREE.BoxGeometry(1.5, 1.5, 0.2);

        // Front Window
        const win1 = new THREE.Mesh(windowGeo, glassMaterial);
        win1.position.set(0, 2.5, 3.1);
        houseGroup.add(win1);

        // Back Window
        const win2 = new THREE.Mesh(windowGeo, glassMaterial);
        win2.position.set(0, 2.5, -3.1);
        houseGroup.add(win2);

        // Door
        const doorGeo = new THREE.BoxGeometry(1.5, 3, 0.2);
        const door = new THREE.Mesh(doorGeo, new THREE.MeshStandardMaterial({ color: 0x555555 }));
        door.position.set(0, 1.5, 3.1);
        houseGroup.add(door);

        // 6. Add House to Scene
        scene.add(houseGroup);

        // 7. Animation Loop
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        // Handle Window Resize
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });

        animate();
    </script>
</body>
</html>
```

### How to use this:
1.  Copy the code block above.
2.  Create a new file on your computer named `house.html`.
3.  Paste the code into that file and save it.
4.  Double-click `house.html` to open it in your web browser.

### What this code does:
*   **Scene Setup:** Creates a 3D environment with a sky-blue background and fog.
*   **Lighting:** Adds ambient light (soft fill) and a directional light (sun) that casts shadows.
*   **Geometry:** Constructs a house using basic shapes:
    *   A `BoxGeometry` for the walls and floor.
    *   A `ConeGeometry` for the roof.
    *   Smaller boxes for windows and a door.
*   **Interactivity:** Includes `OrbitControls`, allowing you to click and drag to rotate around the house and scroll to zoom in/out.
*   **Rendering:** Uses the WebGLRenderer to draw the scene to your screen.
